//! Interactive counter app served over SSH
//!
//! Run with: cargo run --example bubbletea_counter
//! Connect with: ssh -p 2222 localhost

use bubbletea::{Model, Cmd, tea};
use wish::{Server, ServerConfig, Context};

struct Counter {
    count: i32,
    user: String,
}

impl Counter {
    fn new(user: String) -> Self {
        Self { count: 0, user }
    }
}

impl Model for Counter {
    type Message = CounterMsg;

    fn update(&mut self, msg: Self::Message) -> Cmd<Self::Message> {
        match msg {
            CounterMsg::Increment => self.count += 1,
            CounterMsg::Decrement => self.count -= 1,
            CounterMsg::Quit => return tea::quit(),
        }
        Cmd::none()
    }

    fn view(&self) -> String {
        format!(
            "Hello, {}!\n\nCount: {}\n\n[+] increment  [-] decrement  [q] quit",
            self.user, self.count
        )
    }
}

